var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"원♪ 투♬ 원투♬ 짠~","JPN":"ワン♪　 ツー♬　 ワン、ツー♬ 　じゃ～ん。","ENG":"One, ♪ two, ♬ one, two, ♬ tah-dah!","TWN":"一♪二♬一二♬鏘～"},"stage":{"bg":"OFFICE_HEAD","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"냐하핫, 오늘은 다른 때보다 움직임이 좋은 거 같네~","JPN":"にゃははっ、今日はいつもよりキレッキレに踊れてる気がするにゃ～。","ENG":"Nya hah hah, looks like I'm really killing it today!","TWN":"喵哈哈，今天的動作好像比以前靈活很多呢喵～"},"stage":{"bg":"OFFICE_HEAD","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"그러면 이 기세를 몰아서 시청자들이 깜짝 놀랄 안무를 만들어 볼까낭?","JPN":"ほいじゃ、この勢いでリスナーたちが驚くような振り付けを考えてみようかにゃ～？","ENG":"Alright, then. I'm going to choreograph a dance that'll make my fans freak out!","TWN":"那麼就趁著這個氣勢，編一個能讓觀眾驚豔的舞蹈吧喵？"},"stage":{"bg":"OFFICE_HEAD","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"흠, 보미 양은 다른 일은 몰라도 춤 하나만은 누구보다 열심히 추는군.","JPN":"ふむ、ボミ君は普段の生活はともかく、ダンスに関しては誰よりも一生懸命なのだな。","ENG":"Hmm, I see that you're more committed to dancing than anything else.","TWN":"哦，雖然我對普美小姐的其他事情不太瞭解，但跳舞方面她比其他人都要努力呢。"},"stage":{"bg":"OFFICE_HEAD","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"기왕 파견 나왔으니 현장에서도 분발해 주면 좋겠지만 말이야.","JPN":"せっかく現場に派遣されてきたのだから、仕事にも精を出してくれると嬉しいのだが。","ENG":"Although I'd appreciate the same amount of enthusiasm when you're out on the field.","TWN":"既然都被派遣了，要是她在現場也有這個表現就好了。"},"stage":{"bg":"OFFICE_HEAD","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"앗, 사장님? 보고 있었어?","JPN":"あっ、社長？　見てたのにゃ？","ENG":"Oh, Boss? Were you watching me?","TWN":"啊，老闆？您一直都在看嗎？"},"stage":{"bg":"OFFICE_HEAD","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그럼. 직원들이 잘 지내는지 살피는 것도 사장이 해야 할 일 중 하나 아니겠나.","JPN":"ああ、社員達が元気かどうか確かめるのも社長の務めの一つだ。","ENG":"Of course. A great CEO is always on the lookout for his employees' welfare.","TWN":"當然。視察員工們有沒有好好工作，也是老闆該做的事情之一。"},"stage":{"bg":"OFFICE_HEAD","slots":{"L":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L11_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"절대 하릴없이 산책 다니는 건 아닐세!","JPN":"断じて暇つぶしに散歩していたわけではないぞ！","ENG":"I'm not just strolling about because I've got nothing better to do!","TWN":"絕對不是因為沒事幹，所以在閒晃喔！"},"stage":{"bg":"OFFICE_HEAD","slots":{"L":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"그렇구나~","JPN":"そうなんだにゃ～。","ENG":"I see.","TWN":"是這樣喔～"},"stage":{"bg":"OFFICE_HEAD","slots":{"L":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"구경하고 있으면 구경한다고 말해 주지~ 그럼 더 멋진 안무를 준비해 줬을 텐데냥~","JPN":"見に来るって言ってくれればよかったのに～。\\nそしたらもっと素敵な振り付けを用意して披露してたにゃ～。","ENG":"You could've let me know you'd be watching. I would've prepared something even more awesome!","TWN":"如果你想參觀就直說喵～那我就能準備更棒的舞蹈了喵～"},"stage":{"bg":"OFFICE_HEAD","slots":{"L":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그래? 방금 본 춤도 보통이 아니라고 생각했는데?","JPN":"そうか？　さっきのダンスも並大抵のものではないと思ったが？","ENG":"Really? The dance I just saw was pretty impressive, too.","TWN":"是嗎？剛剛的舞蹈也很棒啊？"},"stage":{"bg":"OFFICE_HEAD","slots":{"L":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"냐하♪ 이 정도야 몸풀기징~♬","JPN":"にゃは♪　こんなのは序の口にゃ～♬","ENG":"Nya hah. ♪ I was just getting warmed up. ♬","TWN":"喵哈♪那只是熱身呀～♬"},"stage":{"bg":"OFFICE_HEAD","slots":{"L":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"방금 췄던 춤도 렌즈가 아니라 직접 보면 감흥이 색달랐겠지만~♪","JPN":"さっきのダンスだって、レンズ越しじゃなく生で見たらもっと違ったと思うんだけどにゃ～♪","ENG":"I'm sure you would've enjoyed it more if you saw it yourself, instead of through the robot's cameras. ♪","TWN":"不過剛才的舞如果不是透過鏡頭，而是直接看的話，應該會有完全不同的感受喵～♪"},"stage":{"bg":"OFFICE_HEAD","slots":{"L":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"크흠흠...... 요새 오는 직원들은 다들 눈치가 빠르구만......","JPN":"むむむ……近頃の新入社員はみな察しが良すぎるな……","ENG":"Ahem... I guess all the new employees these days are quite clever...","TWN":"咳咳……最近來的員工觀察力都很好啊……"},"stage":{"bg":"OFFICE_HEAD","slots":{"L":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그, 그나저나 보미 양은 어쩌다가 춤을 추기 시작했나?","JPN":"そ、それはそうと、ボミ君、ダンスを踊り始めたきかっけは何かね？","ENG":"A-anyway, how did you learn to dance so well?","TWN":"話、話說回來，普米小姐跳舞的契機是什麼？"},"stage":{"bg":"OFFICE_HEAD","slots":{"L":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"냐하핫♪ 난 복잡하고 우중충한 분위기는 질색이라서냥~♬","JPN":"にゃははっ♪　ボミは難しいお話とか、テンションが下がったりするのは苦手なのにゃ～♬","ENG":"Nya hah hah! ♪ I just don't like it when people are stressed out and gloomy! ♬","TWN":"喵哈哈♪因為我最討厭陰鬱的氣氛了喵～♬"},"stage":{"bg":"OFFICE_HEAD","slots":{"L":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"그런데 내가 춤을 추면 다들 신나 하잖아. 보미도 춤을 추면 신나니까 일석이조루다가~♬","JPN":"でも、ボミが踊るとみんなが盛り上がるにゃ。踊ってるとボミも楽しくなるから一石二鳥なのにゃ～♬","ENG":"Whenever I dance, everyone gets excited! And I get cheered up myself! One stone, two birds! ♬","TWN":"只要我開始跳舞，大家就會變得很開心；跳起舞來普美也會很開心，也就是一石二鳥喵～♬"},"stage":{"bg":"OFFICE_HEAD","slots":{"L":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그거 참...... 간단하면서도 심오한 이유군 그래.","JPN":"それはまた……シンプルでありながら深い理由だな。","ENG":"That sounds like... a simple but profound reason.","TWN":"那可真是……簡單又深奧的理由呢。"},"stage":{"bg":"OFFICE_HEAD","slots":{"L":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};